var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어휴, 멀리서도 탄내가 진동하네. 보나마나 부품은 죄다 교체해야겠어.","JPN":"うわっ、焦げ臭いぞ。\\nこりゃ見るまでもなく部品は全取っ換えだね。","ENG":"Geez, I can smell the burning from here. I bet you’ll have to change all your parts.","TWN":"哇，遠遠的就可以聞到燒焦味，零件應該全都要換了吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"어쩔 수 없지. 좋은 경험을 한 대가로 치는 수밖에.","JPN":"仕方ない。高い勉強代だったと考えよう。","ENG":"Oh well. I guess that’s the price I paid for a good lesson.","TWN":"沒辦法，就當作是花錢買經驗吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"나야 직접 안 싸워서 모르겠지만…… 얼마나 강했는데 그래?","JPN":"俺は戦ってないからピンと来ないな……どれだけ強かったんだ？","ENG":"I didn’t have the chance to fight him head on... How strong was he?","TWN":"我是沒有直接參與，所以不太清楚……到底是有多厲害？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"배터리가 폭발할 만큼 아찔한 상대였지. 새로운 심장을 달지 않았으면 죽었을 거다.","JPN":"バッテリーが爆発するほどのとんでもない相手だった。\\n新しい心臓を取り付けてなかったら、とっくにくたばってただろう。","ENG":"Strong enough to blow up my battery. I would have died if it wasn’t for the new heart.","TWN":"厲害到電池會爆炸的程度，要不是有你新替我裝上的心臟，我早就一命嗚呼。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"정말? 시험 삼아 달아 본 건데 진짜 도움이 됐다고?","JPN":"マジかよ。試しに取り付けただけなのに、実際に役に立ったのか？","ENG":"Really? It was just a test, and it actually helped?","TWN":"真的假的？我只是裝好玩的欸，結果真的派上用場啦？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그 남자, 강하더군.","JPN":"あの男、本当に強かった。","ENG":"That man was strong.","TWN":"那男人，很強。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"카운터 중에서도 분명 A급……. 아니, S급일지도 모르겠어.","JPN":"カウンターのなかでもきっとA級……いや、S級かもしれない。","ENG":"He must be a Grade A... no, maybe a Grade S Counter.","TWN":"以制裁者來說應該是A級……不，說不定有到S級。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그보다 수집가는 어디 있지?","JPN":"それより収集家はどこだ？","ENG":"By the way, where is the Collector?","TWN":"話說回來，收藏家人呢？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"평의회랑 교신 중이야. 일이 틀어진 것 때문에 저기압이던데.","JPN":"評議会と交信中だよ。計画が狂ったことでご機嫌ななめだったけど。","ENG":"She’s talking to the Council now. She’s in a bad mood because of what happened.","TWN":"她在和評議會通話中。因為事情搞砸了，氣氛不太好的樣子。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"정황은 이해했어.","JPN":"状況は理解した。","ENG":"I understand the situation now.","TWN":"事情的來龍去脈我都知道了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L16_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"갑작스럽게 벌어진 일이라 많이 놀랐겠군. 유감이야.","JPN":"突然のことでさぞ驚いただろうな、残念だ。","ENG":"It was an unexpected accident. I feel for you.","TWN":"事發突然，想必你們應該也受到不少驚嚇，我感到很遺憾。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"여유부릴 때가 아니야. 당장 다른 놈들도 호출해.","JPN":"余裕こいている場合じゃない、今すぐ他の奴らも呼び出せ。","ENG":"This is not the time for comfort. Call the others.","TWN":"現在不是打官腔的時候，趕快找幫手吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"음? 어째서?","JPN":"うん？　なぜだ？","ENG":"Hmm? Why?","TWN":"嗯？為什麼？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그걸 몰라서 묻나?","JPN":"そりゃ聞くまでもないだろ。","ENG":"Don’t you see?","TWN":"你是明知故問嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"이쪽에서 대응 못한 건 인정하지. 다른 녀석들까지 체면을 구기게 만든 것도.","JPN":"俺らが対応に失敗したのは認める。他の奴らの面子まで潰したことも。","ENG":"I admit that I failed. I also admit that I made others look bad.","TWN":"我承認我們這次確實是辦事不力，也害其他人的面子掛不住。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"하지만 이럴 때 뒷짐 지고 구경만 하자고 평의회를 만들지는 않았을 텐데?","JPN":"だが、評議会はこんな時に傍観するだけの機関じゃないだろう？","ENG":"But this is the kind of situation where the Council steps in and helps, rather than sitting back and comforting each other.","TWN":"但評議會創立的目的，應該不是要在這種時候袖手旁觀吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"아, 그 일이라면 걱정할 필요 없네. 상대가 나빴으니까.","JPN":"ああ、その件なら心配ない。相手が悪かったのだから。","ENG":"Oh, don’t worry about it. You just picked the wrong person to fight today.","TWN":"喔～你是說那件事嗎？沒什麼好擔心的，都怪對方不好。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"무슨 소리야?","JPN":"何を言ってるんだ？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"델타 세븐이라는 이름은 들어봤겠지?","JPN":"デルタセブンという名は聞いたことがあるか？","ENG":"Have you heard of Delta Seven?","TWN":"你有聽說過第七三角洲部隊吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"네가 본 남자의 이름은 제이크 워커. 델타 세븐 최강의 스트라이커다.","JPN":"君が見た男の名はジェイク・ウォーカー。デルタセブン最強のストライカーだ。","ENG":"The man you saw was Jake Walker. He’s Delta Seven's number one striker.","TWN":"你見到的那個男人，名叫傑克·沃克，是第七三角洲部隊最強的前鋒。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"군인이 아닌 관리국 소속이었다면 분명 S급 카운터로 등록되었을 거야.","JPN":"軍人ではなく管理局所属だったら、\\nきっとS級カウンターとして登録されていただろう。","ENG":"If he wasn’t a soldier, he would have been registered with the Administration as a Grade S Counter.","TWN":"若他不是軍人，而是隸屬於管理局的話，實力應該會被歸類為S級的制裁者吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"S급이라고? 그 놈이?","JPN":"S級だって？　あいつが？","ENG":"Grade S? Him?","TWN":"那傢伙是S級？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"그래. 비공식 데이터긴 하지만 확실해.","JPN":"そうだ、非公式データだが間違いない。","ENG":"Yes. It’s unofficial, but I’m sure.","TWN":"沒錯，雖然是非官方資料，但確實是如此。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"그걸 감안하면 오히려 빠르게 철수해서 다행이었지.","JPN":"それを考慮すれば、むしろ早く撤退できてよかったほうだ。","ENG":"So I would say you did well by withdrawing quickly.","TWN":"所以你們立刻撤退反而可以說是是明智之舉。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"하지만 결국 리액터는 못 찾았어.","JPN":"けど、結局リアクターは見つからなかった。","ENG":"But we didn’t find the reactor.","TWN":"但我們沒能找到反應爐。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"유용하게 써먹을 데가 수도 없이 많은데……. 제기랄.","JPN":"使い道が山ほどあるのに……くそっ。","ENG":"Think about the possibilities of what we could do with that thing...","TWN":"拿到的話就可以運用在很多地方……該死！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"하하. 걱정 마. 결국 우리가 얻으나, 그들이 얻으나 결과는 다르지 않아.","JPN":"ハハハ、心配するな。\\n我々が手に入れようが、彼らが手に入れようが、結果は変わらない。","ENG":"Haha, don’t worry about it. Whether we find it or they do, it won’t make much of a difference.","TWN":"哈哈，別激動，無論是我們拿到，或是他們拿到，結果都是一樣的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"문제가 생긴다면 다른 곳이 손에 넣었을 때지.","JPN":"問題があるとしたら、第三者が手に入れた時だ。","ENG":"What matters is that someone else finds the reactor.","TWN":"有什麼問題的話，頂多就是其他的地方得到手。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"관리국 말인가? 아니면, 그 망할 코핀 컴퍼니?","JPN":"管理局のことか？　それとも、あのクソコフィンカンパニー？","ENG":"The Administration? Or that dang Coffin Company?","TWN":"你是說管理局嗎？還是那個該死的科芬公司？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"아니, 차라리 그쪽이었으면 좋겠군.","JPN":"いや、むしろそれならまだマシだろう。","ENG":"Oh, they are not our concern.","TWN":"不，我希望是你。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"그보다 훨씬 더 위험한 녀석들이지.","JPN":"それよりも遥かに危険な奴らだ。","ENG":"What I mean is much a more dangerous group...","TWN":"你們比那些傢伙更危險不是嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"아. 그리고 선물로 제프티 바이오테크에서 유출된 자료를 보내 뒀어.","JPN":"ああ、そういえばプレゼントとして\\nジェフティ・バイオテックから流出した資料を送っておいた。","ENG":"Oh. I sent you some leaked info from Jehuty Biotech as a gift.","TWN":"對了，我送了禮物給你，是從傑夫堤生物科技流出的資料。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"스캐빈저와 협상 자료로 쓸 수 있을 거야. 동업자들끼리는 사이 좋게 지내야지.","JPN":"スカベンジャーとの交渉材料として使えるだろう。\\n同業者同士で仲良くしないとな。","ENG":"You’ll be able to use it when you negotiate with the Scavengers. Partners help each other, right?","TWN":"可以當作你和清道夫談判的籌碼，同業之間要好好相處喔。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"……흥. 결국 이번에도 날 장기말로 써먹었다는 소리군.","JPN":"……ふん、結局のところ、今回も俺を駒として使ったってわけだ。","ENG":"Hmpf. So you used me as a pawn again.","TWN":"……哼，意思就是這次也只是想把我當成一顆棋子。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"언제까지 그렇게 잘난 척 할 수 있을지 보자, 빌어먹을 애늙은이 자식.","JPN":"いつまでそう偉そうにしていられるか見ててやるよ。くそガキめ。","ENG":"Let’s see how long you stay cocky, you old soul.","TWN":"我看你可以囂張到什麼時候，老成的傢伙！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};